/* eslint-disable */
// Extend Polaris web component types to allow common HTML attributes
declare namespace JSX {
  interface IntrinsicElements {
    's-app-nav': any;
    's-link': any;
    's-page': any;
    's-section': any;
    's-stack': any;
    's-heading': any;
    's-text': any;
    's-badge': any;
    's-banner': any;
    's-button': any;
    's-text-field': any;
    's-password-field': any;
    's-search-field': any;
    's-select': any;
    's-option': any;
    's-text-area': any;
  }
}
